const { Manifold, CrossSection, label } = api;

// Helper: axis-aligned box from min/max corners
function box(min, max) {
  const s = [max[0] - min[0], max[1] - min[1], max[2] - min[2]];
  const c = [(min[0] + max[0]) / 2, (min[1] + max[1]) / 2, (min[2] + max[2]) / 2];
  return Manifold.cube(s, true).translate(c);
}

// Main 16-unit cube body
const body = Manifold.cube([16, 16, 16], true);

// === HEART SHAPE ===
// Build a blocky heart out of raised cuboids on each face.
// Heart pixel art (5-wide, 5-tall grid, each pixel = 2 units):
//  .XX.XX.   row4 (top) — two bumps
//  XXXXXXX   row3
//  XXXXXXX   row2
//  .XXXXX.   row1
//  ..XXX..   row0
//  ...X...   row-1 (point)
// Center at x=0, z=0; protrudes 1.2 units out from face, overlaps 0.5

// Front face heart (protruding toward -Y)
const fhy = [-8.7, -7.5]; // front protrusion with 0.5 overlap
function fhp(x0, x1, z0, z1) {
  return box([x0, fhy[0], z0], [x1, fhy[1], z1]);
}
// Heart shape: two bumps at top, wide middle, tapers to point
const heartFront =
  fhp(-4, -1, 2.5, 5) // left bump top
  .add(fhp(1, 4, 2.5, 5)) // right bump top
  .add(fhp(-5, 5, 0.5, 3)) // wide middle
  .add(fhp(-4, 4, -1.5, 1)) // upper taper
  .add(fhp(-3, 3, -3.5, -1)) // middle taper
  .add(fhp(-1, 1, -5.5, -3)); // point at bottom

// Back face heart (protruding toward +Y)
const bhy = [7.5, 8.7];

function bhp(x0, x1, z0, z1) {
  return box([x0, bhy[0], z0], [x1, bhy[1], z1]);
}
const heartBack =
  bhp(-4, -1, 2.5, 5)
  .add(bhp(1, 4, 2.5, 5))
  .add(bhp(-5, 5, 0.5, 3))
  .add(bhp(-4, 4, -1.5, 1))
  .add(bhp(-3, 3, -3.5, -1))
  .add(bhp(-1, 1, -5.5, -3));

// Left face heart (protruding toward -X)
const lhx = [-8.7, -7.5];

function lhp(y0, y1, z0, z1) {
  return box([lhx[0], y0, z0], [lhx[1], y1, z1]);
}
const heartLeft =
  lhp(-4, -1, 2.5, 5)
  .add(lhp(1, 4, 2.5, 5))
  .add(lhp(-5, 5, 0.5, 3))
  .add(lhp(-4, 4, -1.5, 1))
  .add(lhp(-3, 3, -3.5, -1))
  .add(lhp(-1, 1, -5.5, -3));

// Right face heart (protruding toward +X)
const rhx = [7.5, 8.7];

function rhp(y0, y1, z0, z1) {
  return box([rhx[0], y0, z0], [rhx[1], y1, z1]);
}
const heartRight =
  rhp(-4, -1, 2.5, 5)
  .add(rhp(1, 4, 2.5, 5))
  .add(rhp(-5, 5, 0.5, 3))
  .add(rhp(-4, 4, -1.5, 1))
  .add(rhp(-3, 3, -3.5, -1))
  .add(rhp(-1, 1, -5.5, -3));

const hearts = heartFront.add(heartBack).add(heartLeft).add(heartRight);

// === EDGE BARS ===
// Raised bars along each of the 12 cube edges, 1.5 wide × 1 tall, full length
// 4 vertical edges (along Z)
const ev = 1.5; // edge bar half-width
const et = 1.0; // edge bar protrusion thickness
const eL = 16; // full cube edge length

// Corner positions at ±8, bar spans full length of edge
// Vertical edges — run along Z
function vEdgeBar(sx, sy) {
  // Centered on the corner at (sx*8, sy*8), runs z = -8..8
  return box([sx * 8 - et, sy * 8 - et, -8], [sx * 8 + et, sy * 8 + et, 8]);
}

// Horizontal edges along X
function hxEdgeBar(sy, sz) {
  return box([-8, sy * 8 - et, sz * 8 - et], [8, sy * 8 + et, sz * 8 + et]);
}

// Horizontal edges along Y
function hyEdgeBar(sx, sz) {
  return box([sx * 8 - et, -8, sz * 8 - et], [sx * 8 + et, 8, sz * 8 + et]);
}

const edgeBars =
  // 4 vertical edges
  vEdgeBar(-1, -1).add(vEdgeBar(1, -1)).add(vEdgeBar(-1, 1)).add(vEdgeBar(1, 1))
  // 4 edges along X (top and bottom)
  .add(hxEdgeBar(-1, -1)).add(hxEdgeBar(1, -1))
  .add(hxEdgeBar(-1, 1)).add(hxEdgeBar(1, 1))
  // 4 edges along Y (front/back at top and bottom)
  .add(hyEdgeBar(-1, -1)).add(hyEdgeBar(1, -1))
  .add(hyEdgeBar(-1, 1)).add(hyEdgeBar(1, 1));

return label(body, 'body')
  .add(label(hearts, 'hearts'))
  .add(label(edgeBars, 'edges'));
